1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	type Item = {
12	  type: string;
13	  material?: string;
14	  enchantment?: number;
15	  cursed?: boolean;
16	};
17	type QuoteStep = { op: "quote"; items: Item[] };
18	type Step = QuoteStep;
19	type Customer = { yearsWithMHPCO: number };
20	type Scenario = { customer: Customer; steps: Step[] };
21	
22	const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;
23	
24	const FIRST_INSURANCE_RATE = 0.1;
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	const BLOCK_SIZE = 3;
28	const BLOCK_BASE_PREMIUM = 60;
29	
30	const countByType = (items: Item[]): Map<string, number> => {
31	  const counts = new Map<string, number>();
32	  for (const item of items) {
33	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
34	  }
35	  return counts;
36	};
37	
38	const groupBase = (type: string, count: number): number =>
39	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
40	    ? BLOCK_BASE_PREMIUM
41	    : count * basePremiumFor(type);
42	
43	const policyBase = (items: Item[]): number =>
44	  Array.from(countByType(items)).reduce(
45	    (total, [type, count]) => total + groupBase(type, count),
46	    0,
47	  );
48	
49	const firstInsuranceSurcharge = (base: number): number =>
50	  base * FIRST_INSURANCE_RATE;
51	
52	const LOYALTY_RATE = 0.2;
53	const LOYALTY_THRESHOLD_YEARS = 2;
54	
55	const loyaltyDiscount = (base: number, customer: Customer): number =>
56	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_RATE : 0;
57	
58	const CURSE_RATE = 0.5;
59	const HIGH_ENCHANTMENT_RATE = 0.3;
60	const HIGH_ENCHANTMENT_THRESHOLD = 5;
61	
62	const surchargeWhen = (item: Item, applies: boolean, rate: number): number =>
63	  applies ? basePremiumFor(item.type) * rate : 0;
64	
65	const curseSurcharge = (item: Item): number =>
66	  surchargeWhen(item, item.cursed === true, CURSE_RATE);
67	
68	const highEnchantmentSurcharge = (item: Item): number =>
69	  surchargeWhen(
70	    item,
71	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
72	    HIGH_ENCHANTMENT_RATE,
73	  );
74	
75	const itemSurcharges = (items: Item[]): number =>
76	  items.reduce(
77	    (sum, item) => sum + curseSurcharge(item) + highEnchantmentSurcharge(item),
78	    0,
79	  );
80	
81	const quotePremium = (items: Item[], customer: Customer): number => {
82	  const base = policyBase(items);
83	  const surcharges = itemSurcharges(items);
84	  return Math.ceil(
85	    base +
86	      surcharges -
87	      loyaltyDiscount(base, customer) +
88	      firstInsuranceSurcharge(base) +
89	      PROCESSING_FEE,
90	  );
91	};
92	
93	export const processScenario = (scenario: Scenario): unknown => {
94	  const results = scenario.steps.map((step) => ({
95	    premium: quotePremium(step.items, scenario.customer),
96	  }));
97	  return { results };
98	};
